// ─── Mercator projection calibrated to PROTrack viewBox 0 0 960 440 ─
// Fitted against PROTrack reference points: ZRH(502.8,148.1), NYC(282.7,165.2),
// PAR(486.3,144.0), SIN(756.9,244.9) — all match within <0.1px
function projectLatLon(lat: number, lon: number): [number, number] {
  // Longitude: linear mapping [-180, 180] → [0, 960]
  const x = ((lon + 180) / 360) * 960

  // Latitude: Mercator projection with PROTrack-calibrated scale/offset
  const latRad = (lat * Math.PI) / 180
  const mercN = Math.log(Math.tan(Math.PI / 4 + latRad / 2))
  // y = 247.4 - 105.5 * mercN (derived from PROTrack reference points)
  const y = 247.4 - mercN * 105.5

  return [Math.max(0, Math.min(960, x)), Math.max(0, Math.min(440, y))]
}

// ─── Longitude to SVG x in viewBox 0 0 960 440 ─────────────
function lonToX(lon: number): number {
  return ((lon + 180) / 360) * 960
}

// ─── Format time for a given IANA timezone ──────────────────
function formatTimeForTimezone(iana: string): string {
  try {
    return new Date().toLocaleTimeString('de-CH', {
      hour: '2-digit',
      minute: '2-digit',
      timeZone: iana,
      hour12: false,
    })
  } catch {
    return '--:--'
  }
}

// ─── Label placement configuration for overlapping locations ─
interface LabelConfig {
  anchor: 'start' | 'middle' | 'end'
  dx: number
  dy: number
  showAlways: boolean
}

function getLabelConfig(code: string): LabelConfig {
  switch (code) {
    // Zurich locations cluster — spread labels to avoid overlap
    case 'ZRH-STZ':
      return { anchor: 'start', dx: 8, dy: 6, showAlways: true }
    case 'ZRH-BAS':
      return { anchor: 'start', dx: 0, dy: 0, showAlways: false } // hover only
    case 'ZRH-NUGOLO':
      return { anchor: 'start', dx: 0, dy: 0, showAlways: false } // hover only
    case 'FRA-DC':
      return { anchor: 'middle', dx: 0, dy: -12, showAlways: true }
    case 'MUC-OFF':
      return { anchor: 'start', dx: 10, dy: 3, showAlways: true }
    default:
      return { anchor: 'middle', dx: 0, dy: -12, showAlways: true }
  }
}

